### Create Lambda Function with Dependency Management

Source: https://context7.com/vercel/vercel/llms.txt

Builds a serverless Lambda function by downloading source files, detecting Node.js version, installing dependencies with caching, running build scripts, and tracing only necessary node_modules. Returns configured Lambda with environment variables, memory allocation, and routing configuration. Requires @vercel/build-utils and @vercel/nft for file tracing.

```javascript
const {
  createLambda,
  glob,
  download,
  FileBlob,
  FileFsRef,
  runNpmInstall,
  getNodeVersion,
  spawnAsync,
} = require('@vercel/build-utils');
const path = require('path');

async function buildFunction(options) {
  const { files, entrypoint, workPath, config, meta } = options;

  // Download source files to work directory
  console.log('Downloading source files...');
  await download(files, workPath, meta);

  // Detect and validate Node.js version
  const nodeVersion = await getNodeVersion(
    workPath,
    config.nodeVersion,
    config,
    meta
  );
  console.log(`Using Node.js ${nodeVersion.runtime}`);

  // Install dependencies with caching
  console.log('Installing dependencies...');
  await runNpmInstall(
    workPath,
    ['--prefer-offline'],
    { NODE_ENV: 'production' },
    meta
  );

  // Run build script if present
  const packageJson = path.join(workPath, 'package.json');
  try {
    await spawnAsync('npm', ['run', 'build'], {
      cwd: workPath,
      env: { ...process.env, NODE_ENV: 'production' },
    });
    console.log('Build completed successfully');
  } catch (error) {
    console.log('No build script or build failed:', error.message);
  }

  // Gather output files
  const outputFiles = await glob('**', {
    cwd: workPath,
    ignore: [
      'node_modules/**',
      '.git/**',
      '.vercel/**',
      'tests/**',
      '**/*.test.js',
      '**/*.spec.js',
    ],
  });

  // Include only necessary node_modules using tree-shaking
  const { nodeFileTrace } = require('@vercel/nft');
  const entrypointPath = path.join(workPath, entrypoint);
  const trace = await nodeFileTrace([entrypointPath], {
    base: workPath,
    processCwd: workPath,
  });

  const traceFiles = {};
  for (const file of trace.fileList) {
    traceFiles[file] = await FileFsRef.fromFsPath({
      fsPath: path.join(workPath, file),
    });
  }

  // Create Lambda function
  const lambda = createLambda({
    files: {
      ...outputFiles,
      ...traceFiles,
    },
    handler: entrypoint.replace(/\.(js|ts)$/, '.handler'),
    runtime: nodeVersion.runtime,
    environment: {
      NODE_ENV: 'production',
      ...config.env,
    },
    regions: config.regions || ['iad1'],
    maxDuration: config.maxDuration || 10,
    memory: config.memory || 1024,
    supportsResponseStreaming: config.supportsResponseStreaming || false,
  });

  return {
    output: lambda,
    watch: ['api/**', 'lib/**'],
    routes: config.routes,
  };
}

// Cache node_modules for faster rebuilds
async function prepareCache({ workPath }) {
  return glob('node_modules/**', workPath);
}

module.exports = { build: buildFunction, prepareCache, version: 3 };
```

