### Detect Framework and Configure Build Settings - JavaScript

Source: https://context7.com/vercel/vercel/llms.txt

Detects the web framework in a project and extracts framework-specific build configuration. Uses LocalFileSystemDetector to scan the project directory, identifies the framework from a predefined list, and returns build settings including build command, dev command, install command, output directory, and environment variable prefix. Returns default configuration if no framework is detected.

```javascript
const { detectFramework } = require('@vercel/fs-detectors');
const { LocalFileSystemDetector } = require('@vercel/fs-detectors');
const frameworks = require('@vercel/frameworks');

async function detectAndConfigure(projectPath) {
  const fs = new LocalFileSystemDetector(projectPath);

  const detectedFramework = await detectFramework({
    fs,
    frameworkList: frameworks,
  });

  if (!detectedFramework) {
    console.log('No framework detected, using default configuration');
    return {
      buildCommand: 'npm run build',
      outputDirectory: 'dist',
      devCommand: 'npm run dev',
      installCommand: 'npm install',
    };
  }

  console.log(`Detected framework: ${detectedFramework.name}`);
  console.log(`Framework slug: ${detectedFramework.slug}`);

  const settings = {
    framework: detectedFramework.slug,
    buildCommand: detectedFramework.settings.buildCommand?.value ||
                  detectedFramework.settings.buildCommand?.placeholder,
    devCommand: detectedFramework.settings.devCommand?.value ||
                detectedFramework.settings.devCommand?.placeholder,
    installCommand: detectedFramework.settings.installCommand?.value ||
                    detectedFramework.settings.installCommand?.placeholder || 'npm install',
    outputDirectory: detectedFramework.settings.outputDirectory?.value ||
                     detectedFramework.settings.outputDirectory?.placeholder,
    publicDirectory: detectedFramework.settings.publicDirectory?.placeholder,
  };

  if (detectedFramework.useRuntime) {
    settings.functions = {
      [detectedFramework.useRuntime.src]: {
        runtime: detectedFramework.useRuntime.use,
      },
    };
  }

  if (detectedFramework.envPrefix) {
    settings.envPrefix = detectedFramework.envPrefix;
    console.log(`Environment variables should be prefixed with: ${detectedFramework.envPrefix}`);
  }

  console.log('Build configuration:', settings);
  return settings;
}

module.exports = { detectAndConfigure };
```

