### Detect Builders for Project Files - JavaScript

Source: https://context7.com/vercel/vercel/llms.txt

Detects appropriate builders for files in a project by scanning the project directory and reading package.json. Uses glob to get file list and detectBuilders to match files with their corresponding builders. Returns an array of builders with source paths, builder names, versions, and optional configuration. Requires @vercel/build-utils and filesystem access.

```javascript
const { detectBuilders } = require('@vercel/fs-detectors');
const path = require('path');
const fs = require('fs');
const { glob } = require('@vercel/build-utils');

async function detectBuildersForProject(projectPath) {
  const files = Object.keys(await glob('**', projectPath));

  let pkg = null;
  const pkgPath = path.join(projectPath, 'package.json');
  if (fs.existsSync(pkgPath)) {
    pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf-8'));
  }

  const builders = await detectBuilders(files, pkg, {
    projectSettings: {
      framework: 'nextjs',
    },
  });

  console.log('Detected builders:');
  builders.forEach(builder => {
    console.log(`  ${builder.src} -> ${builder.use}@${builder.version || 'latest'}`);
    if (builder.config) {
      console.log(`    Config:`, builder.config);
    }
  });

  return builders;
}

module.exports = { detectBuildersForProject };
```

