### Create Edge Function with esbuild Bundling

Source: https://context7.com/vercel/vercel/llms.txt

Bundles an edge function into a single ESM file using esbuild with optimizations for Vercel's V8 isolate runtime. Generates source maps, applies tree-shaking, and creates an EdgeFunction object with global region deployment. Requires esbuild for bundling and @vercel/build-utils for file handling.

```javascript
const { EdgeFunction, FileBlob } = require('@vercel/build-utils');

async function buildEdgeFunction(options) {
  const { files, entrypoint, workPath, config } = options;

  // Edge functions require bundling into a single file
  const esbuild = require('esbuild');
  const path = require('path');
  const fs = require('fs');

  const entrypointPath = path.join(workPath, entrypoint);
  const outputPath = path.join(workPath, '.vercel', 'output', 'middleware.js');

  // Bundle with esbuild for edge runtime
  await esbuild.build({
    entryPoints: [entrypointPath],
    bundle: true,
    outfile: outputPath,
    format: 'esm',
    target: 'es2022',
    platform: 'browser',
    conditions: ['edge-light', 'worker', 'browser'],
    mainFields: ['browser', 'module', 'main'],
    external: [],
    minify: true,
    sourcemap: true,
    treeShaking: true,
  });

  const bundledCode = fs.readFileSync(outputPath, 'utf-8');

  // Create Edge Function
  const edgeFunction = new EdgeFunction({
    deploymentTarget: 'v8-worker',
    name: path.basename(entrypoint, path.extname(entrypoint)),
    entrypoint: 'middleware.js',
    files: {
      'middleware.js': new FileBlob({ data: bundledCode }),
      'middleware.js.map': new FileBlob({
        data: fs.readFileSync(`${outputPath}.map`),
      }),
    },
    regions: config.regions || ['iad1', 'sfo1', 'cdg1'],
    framework: config.framework,
  });

  return {
    output: edgeFunction,
    routes: [
      {
        src: config.matcher || '/(.*)',
        middlewarePath: path.basename(entrypoint, path.extname(entrypoint)),
        continue: true,
      },
    ],
  };
}

module.exports = { build: buildEdgeFunction, version: 3 };
```

