### Database Connection Pooling for PostgreSQL in Vercel Functions

Source: https://context7.com/vercel/vercel/llms.txt

Implements connection pooling for PostgreSQL databases in Vercel serverless functions with automatic connection lifecycle management using attachDatabasePool. Provides GET and POST handlers for user queries and inserts with error handling, connection timeout configuration, and configurable memory and duration limits. Requires pg and @vercel/functions packages.

```javascript
import { attachDatabasePool } from '@vercel/functions/db-connections';
import { Pool } from 'pg';

// Create PostgreSQL connection pool
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 1,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000
});

// Attach database pool for connection management
attachDatabasePool(pool);

export async function GET(request) {
  const url = new URL(request.url);
  const userId = url.searchParams.get('id');

  try {
    // Query with automatic connection management
    const result = await pool.query(
      'SELECT * FROM users WHERE id = $1',
      [userId]
    );

    if (result.rows.length === 0) {
      return Response.json({ error: 'User not found' }, { status: 404 });
    }

    return Response.json(result.rows[0]);
  } catch (error) {
    console.error('Database query failed:', error);
    return Response.json(
      { error: 'Database query failed' },
      { status: 500 }
    );
  }
}

export async function POST(request) {
  const body = await request.json();
  const { name, email } = body;

  try {
    const result = await pool.query(
      'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *',
      [name, email]
    );

    return Response.json(result.rows[0], { status: 201 });
  } catch (error) {
    console.error('Database insert failed:', error);
    return Response.json(
      { error: 'Failed to create user' },
      { status: 500 }
    );
  }
}

export const config = {
  maxDuration: 10,
  memory: 1024
};
```

